"use strict";(globalThis.webpackChunkmy_website=globalThis.webpackChunkmy_website||[]).push([[7004],{5240(e,o,t){t.r(o),t.d(o,{assets:()=>h,contentTitle:()=>r,default:()=>l,frontMatter:()=>i,metadata:()=>s,toc:()=>d});const s=JSON.parse('{"id":"stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-8","title":"Discourses \u2014 Book 2, Chapter 8","description":"Book 2 \u2014 Chapter 8","source":"@site/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-8.md","sourceDirName":"stoicism/epictetus/discourses/book-2","slug":"/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-8","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-8","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":9,"frontMatter":{"sidebar_position":9,"title":"Discourses \u2014 Book 2, Chapter 8","sidebar_label":"Book 2, Ch. 8"},"sidebar":"philosophersSidebar","previous":{"title":"Book 2, Ch. 7","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-7"},"next":{"title":"Book 2, Ch. 9","permalink":"/justinus/docs/stoicism/epictetus/discourses/book-2/discourses-book-2-chapter-9"}}');var n=t(4848),a=t(8453);const i={sidebar_position:9,title:"Discourses \u2014 Book 2, Chapter 8",sidebar_label:"Book 2, Ch. 8"},r="Discourses",h={},d=[{value:"Book 2 \u2014 Chapter 8",id:"book-2--chapter-8",level:2},{value:"What Is The True Nature Of The Good",id:"what-is-the-true-nature-of-the-good",level:3},{value:"Sonnet 4.6 Summary",id:"sonnet-46-summary",level:2},{value:"Text",id:"text",level:2}];function u(e){const o={em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",p:"p",...(0,a.R)(),...e.components},{Details:t}=o;return t||function(e,o){throw new Error("Expected "+(o?"component":"object")+" `"+e+"` to be defined: you likely forgot to import, pass, or provide it.")}("Details",!0),(0,n.jsxs)(n.Fragment,{children:[(0,n.jsxs)("div",{style:{textAlign:"center"},children:[(0,n.jsx)(o.header,{children:(0,n.jsx)(o.h1,{id:"discourses",children:"Discourses"})}),(0,n.jsx)(o.h2,{id:"book-2--chapter-8",children:"Book 2 \u2014 Chapter 8"}),(0,n.jsx)(o.h3,{id:"what-is-the-true-nature-of-the-good",children:"What Is The True Nature Of The Good"})]}),"\n",(0,n.jsx)(o.p,{children:(0,n.jsx)(o.em,{children:"Translated by P.E. Matheson (Oxford: Clarendon Press, 1916)"})}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Sonnet 4.6 Summary"}),(0,n.jsx)(o.h2,{id:"sonnet-46-summary",children:"Sonnet 4.6 Summary"}),(0,n.jsx)(o.p,{children:"God is beneficent; the good is beneficent; therefore the good shares God's nature. God's nature is intelligence, knowledge, right reason \u2014 not flesh or land or fame. The good therefore lies in reason, not in anything plants or animals possess. Animals can handle impressions but can't reflect on that handling; they are means for others, not ends in themselves. Humans are fragments of God, principal works, capable of understanding the divine governance."}),(0,n.jsx)(o.p,{children:"The chapter's emotional center is the image of bearing God within you without knowing it, defiling that presence with unclean thoughts and careless actions. You wouldn't behave that way before a statue of Zeus \u2014 yet God is actually present, not in bronze but in you. The orphan entrusted to your care analogy makes it personal: God entrusted you to yourself. Are you keeping the trust?"}),(0,n.jsx)(o.p,{children:"The closing is a statement of what philosophical \"sinews\" actually look like: will that doesn't fail, avoidance that doesn't fall into evil, appropriate impulse, steady purpose, non-precipitate assent. Not the absence of death or illness \u2014 but dying and bearing illness as a god does."})]}),"\n",(0,n.jsxs)(t,{open:!0,children:[(0,n.jsx)("summary",{children:"Text"}),(0,n.jsx)(o.h2,{id:"text",children:"Text"}),(0,n.jsx)(o.p,{children:"GOD is beneficent, but the good also is beneficent. It is natural therefore that the true nature of the good should be in the same region as the true nature of God. What then is the nature of God? Is it flesh? God forbid. Land? God forbid. Fame? God forbid. It is intelligence, knowledge, right reason. In these then and nowhere else seek the true nature of the good. Do you look for it in a plant? No. Or in an irrational creature? No. If then you seek it in what is rational why do you seek it elsewhere than in what distinguishes it from irrational things? Plants have not the faculty of dealing with impressions; therefore you do not predicate 'good' of them."}),(0,n.jsx)(o.p,{children:"The good then demands power to deal with impressions. Is that all it demands? If that be all, you must say that other animals also are capable of good and of happiness and unhappiness. But you do not say so and you are right, for whatever power they may have to deal with impressions, they have not the power to understand how they do so, and with good reason, for they are subservient to others, and are not of primary importance."}),(0,n.jsx)(o.p,{children:"Take the ass, for instance, is it born to be of primary importance? No; it is born because we had need of a back able to bear burdens. Nay, more, we had need that it should walk; therefore it has further received the power of dealing with impressions, for else it could not have walked. Beyond that its powers cease. But if the ass itself had received the power to understand how it deals with impressions, then it is plain that reason would have required that it should not have been subject to us or have supplied these needs, but should have been our equal and like ourselves. Will you not then seek the true nature of the good in that, the want of which makes you refuse to predicate good of other things?"}),(0,n.jsx)(o.p,{children:"'What do you mean? Are not they too God's works?'"}),(0,n.jsx)(o.p,{children:"They are, but not His principal works, nor parts of the Divine. But"}),(0,n.jsx)(o.p,{children:"you are a principal work, a fragment of God Himself, you have in yourself a part of Him. Why then are you ignorant of your high birth? Why do you not know whence you have come? Will you not remember, when you eat, who you are that eat, and whom you are feeding, and the same in your relations with women? When you take part in society, or training, or conversation, do you not know that it is God you are nourishing and training? You bear God about with you, poor wretch, and know it not. Do you think I speak of some external god of silver or gold? No, you bear Him about within you and are unaware that you are defiling Him with unclean thoughts and foul actions. If an image of God were present, you would not dare to do any of the things you do; yet when God Himself is present within you and sees and hears all things, you are not ashamed of thinking and acting thus: O slow to understand your nature, and estranged from God!"}),(0,n.jsx)(o.p,{children:"Again, when we send a young man from school to the world of action, why is it that we fear that he may do something amiss--in eating, in relations with women, that he may be humbled by wearing rags, or puffed up by fine clothes?"}),(0,n.jsx)(o.p,{children:"He does not know the God that is in him, he knows not in whose company he is going. Can we allow him to say, 'I would fain have you with me'? Have you not God there? and, having Him, do you look for any one else? Will He tell you anything different from this? Why, if you were a statue wrought by Phidias--his Zeus or his Athena--you would have remembered what you are and the Craftsman who made you, and if you had any intelligence, you would have tried to do nothing unworthy of him who made you or of yourself, and to bear yourself becomingly in men's eyes. But as it is, do you, whom Zeus has made, for that reason take no thought what manner of man you will show yourself? Yet what comparison is there between the one artificer and the other or the one work and the other? What work of art, for instance, has in itself the faculties of which it gives indication in its structure? Is it not stone or bronze or gold or ivory? Even the Athena of Phidias having once for all stretched out her hand and received the Victory upon it stands thus for all time, but the works of God are endowed with movement and breath, and have the faculty of dealing with impressions and of testing them."}),(0,n.jsx)(o.p,{children:"When this Craftsman has made you, do you dishonour his work? Nay, more, He not only made you, but committed you as a trust to yourself and none other. Will you not remember this, but even dishonour the trust committed to you?"}),(0,n.jsx)(o.p,{children:"If God had committed some orphan to your care, would you have neglected him so? Yet He has entrusted your own self to you and He says, 'I had none other more trustworthy than you: keep this man for"}),(0,n.jsx)(o.p,{children:"me such as he is born to be, modest, faithful, high-minded, undismayed, free from passion and tumult.' After that, do you refuse to keep him so?"}),(0,n.jsx)(o.p,{children:"But they will say, 'Where has this man got his high looks and his lofty countenance?'"}),(0,n.jsx)(o.p,{children:"Nay, I have not got them yet as I ought: for as yet I have not confidence in what I have learnt and assented to, I still fear my own weakness. Only let me gain confidence and then you shall see a proper aspect and a proper bearing, then I will show you the statue as it is when it is finished and polished. What think you? That this means proud looks? Heaven forbid! Does Zeus of Olympia wear proud looks? No, but his gaze is steadfast, as his should be who is to say:"}),(0,n.jsx)(o.p,{children:"For my word cannot be taken back, nor can it deceive."}),(0,n.jsx)(o.p,{children:"[Homer, Iliad, I. 256]"}),(0,n.jsx)(o.p,{children:"[paragraph continues] Such will I show myself to you--faithful, self-respecting, noble, free from tumult."}),(0,n.jsx)(o.p,{children:"'Do you mean, free from death and old age and disease?'"}),(0,n.jsx)(o.p,{children:"No, but as one who dies as a god, and who bears illness like a god. These are my possessions, these my faculties; all others are beyond me. I will show you the sinews of a philosopher."}),(0,n.jsx)(o.p,{children:"'What do you mean by sinews?'"}),(0,n.jsx)(o.p,{children:"Will to achieve that fails not, will to avoid that falls not into evil, impulse to act appropriately, strenuous purpose, assent that is not precipitate. This is what you shall see."})]})]})}function l(e={}){const{wrapper:o}={...(0,a.R)(),...e.components};return o?(0,n.jsx)(o,{...e,children:(0,n.jsx)(u,{...e})}):u(e)}},8453(e,o,t){t.d(o,{R:()=>i,x:()=>r});var s=t(6540);const n={},a=s.createContext(n);function i(e){const o=s.useContext(a);return s.useMemo(function(){return"function"==typeof e?e(o):{...o,...e}},[o,e])}function r(e){let o;return o=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:i(e.components),s.createElement(a.Provider,{value:o},e.children)}}}]);